module RefModule(
    CLOCK,
    RESET,
    x,
    y,
    DIFF
);input CLOCK, RESET;
    input [11:0] x, y;
    output reg [11:0] DIFF;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge CLOCK or posedge RESET or posedge dbg_halt) begin
        if (RESET) begin
            DIFF <= 0;
        end else begin
            DIFF <= (x > y) ? x - y : y - x;
        end
    end

endmodule
